-- StrandFerma fix (XOR protected, LuaJIT 64-bit bytecode)
local bit = require("bit")
local function xor_decrypt(data, key)
    local res = {}
    local kl = #key
    for i = 1, #data do
        res[i] = string.char(bit.bxor(data:byte(i), key:byte(((i-1) % kl) + 1)))
    end
    return table.concat(res)
end

